.darma-loader-demo-spinner {
  display: inline-block;
  width: 54px;
  height: 54px;
  border-radius: 50%;
  border: 5px solid color-mix(in srgb, var(--loader-color, #6366f1) 18%, transparent);
  border-top-color: var(--loader-color, #6366f1);
  animation: darma-loader-demo-spinner-spin 0.85s linear infinite;
}
@keyframes darma-loader-demo-spinner-spin { to { transform: rotate(360deg); } }

